import{_ as a,c as e,o as t,b as m}from"./app.1117c437.js";const l='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-05T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/6/index.md"}',r={},p=m('<div class="stanza"><a href="#s2.6" id="s2.6" class="num">2.6</a><div class="sans"><p>\u0924\u0926\u0924\u094D\u0930 \u092E\u0941\u0926\u094D\u0930\u093E\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0938\u093E\u0926\u0928\u0947\u093D\u092A\u093F\u2014</p><blockquote><p><strong>\u0917\u0941\u0930\u0941\u0930\u0941\u092A\u093E\u092F\u0903\u0965\u096C\u0965</strong></p></blockquote><p>\u0917\u0943\u0923\u093E\u0924\u094D\u092F\u0941\u092A\u0926\u093F\u0936\u0924\u093F \u0924\u093E\u0924\u094D\u0924\u094D\u0935\u093F\u0915\u092E\u0930\u094D\u0925\u092E\u093F\u0924\u093F \u0917\u0941\u0930\u0941\u0903 \u0938\u094B\u093D\u0924\u094D\u0930 \u0935\u094D\u092F\u093E\u092A\u094D\u0924\u093F\u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0915\u0924\u094D\u0935\u0947\u0928\u094B\u092A\u093E\u092F\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u0938 \u0917\u0941\u0930\u0941\u0930\u094D\u092E\u0924\u094D\u0938\u092E\u0903 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u0915\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0924\u094D\u0935\u0947\u0935\u092E\u093E\u0926\u093F\u092A\u094D\u0930\u0938\u093F\u0926\u094D\u0927\u0924\u094D\u0935\u093E\u0928\u094D\u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964</p><blockquote><p>\u0905\u0917\u093E\u0927\u0938\u0902\u0936\u092F\u093E\u092E\u094D\u092D\u094B\u0927\u093F\u0938\u092E\u0941\u0924\u094D\u0924\u0930\u0923\u0924\u093E\u0930\u093F\u0923\u0940\u092E\u094D\u0964<br> \u0935\u0928\u094D\u0926\u0947 \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u092A\u0926\u093E\u0902 \u091A\u093F\u0924\u094D\u0930\u093E\u0902 \u0924\u093E\u0902 \u0917\u0941\u0930\u0941\u092D\u093E\u0930\u0924\u0940\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u2014 \u092A\u093E\u0930\u094D\u092F\u0928\u094D\u0924\u093F\u0915\u094B\u0915\u094D\u0924\u094D\u092F\u093E \u091A\u0948\u0924\u0926\u092A\u093F \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u0947\u0935\u0964</p><p>\u0917\u0941\u0930\u0941\u0930\u094D\u0935\u093E \u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u0928\u0941\u0917\u094D\u0930\u093E\u0939\u093F\u0915\u093E \u0936\u0915\u094D\u0924\u093F\u0903\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0902 \u0924\u0926\u0947\u0935\u094B\u0915\u094D\u0924\u0902 \u0917\u0941\u0930\u0941\u0935\u0915\u094D\u0924\u094D\u0930\u0902 \u0924\u0926\u0941\u091A\u094D\u092F\u0924\u0947\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u0924\u094D\u0930\u093F\u0936\u093F\u0930\u094B\u092D\u0948\u0930\u0935\u0947\u093D\u092A\u093F</p><blockquote><p>\u0917\u0941\u0930\u094B\u0930\u094D\u0917\u0941\u0930\u0941\u0924\u0930\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0917\u0941\u0930\u0941\u0935\u0915\u094D\u0924\u094D\u0930\u0917\u0924\u093E \u092D\u0935\u0947\u0924\u094D\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u0948\u0935\u093E\u0935\u0915\u093E\u0936\u0902 \u0926\u0926\u0924\u094D\u092F\u0941\u092A\u093E\u092F\u0903\u0965\u096C\u0965</p></div><hr><div class="trans"><p>Tadatra mudr\u0101mantrav\u012Bry\u0101s\u0101dane&#39;pi\u2014</p><blockquote><p><strong>Gururup\u0101ya\u1E25||6||</strong></p></blockquote><p>G\u1E5B\u1E47\u0101tyupadi\u015Bati t\u0101ttvikamarthamiti guru\u1E25 so&#39;tra vy\u0101ptipradar\u015Bakatvenop\u0101ya\u1E25| Tadukta\u1E41 \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>Sa gururmatsama\u1E25 prokto mantrav\u012Bryaprak\u0101\u015Baka\u1E25|</p></blockquote><p>iti| Spande tvevam\u0101diprasiddhatv\u0101nna sa\u1E45g\u1E5Bh\u012Btam|</p><blockquote><p>Ag\u0101dhasa\u1E41\u015Bay\u0101mbhodhisamuttara\u1E47at\u0101ri\u1E47\u012Bm|<br> Vande vicitr\u0101rthapad\u0101\u1E41 citr\u0101\u1E41 t\u0101\u1E41 gurubh\u0101rat\u012Bm||</p></blockquote><p>iti\u2014 p\u0101ryantikokty\u0101 caitadapi sa\u1E45g\u1E5Bh\u012Btameva|</p><p>Gururv\u0101 p\u0101rame\u015Bvaryanugr\u0101hik\u0101 \u015Bakti\u1E25| Yathokta\u1E41 \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>\u015Aakticakra\u1E41 tadevokta\u1E41 guruvaktra\u1E41 taducyate|</p></blockquote><p>iti| \u015Ar\u012Bmantri\u015Birobhairave&#39;pi</p><blockquote><p>Gurorgurutar\u0101 \u015Baktirguruvaktragat\u0101 bhavet|</p></blockquote><p>iti| Saiv\u0101vak\u0101\u015Ba\u1E41 dadatyup\u0101ya\u1E25||6||</p></div><hr><p>\u0422\u0435\u043F\u0435\u0440\u044C \u0437\u0434\u0435\u0441\u044C <em>(tad atra)</em>, \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F <em>(\u0101s\u0101dane)</em> \u0441\u0438\u043B\u044B <em>(v\u012Brya)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em> [\u0438] \u043C\u0443\u0434\u0440\u044B <em>(mudr\u0101... api)</em>, [\u015Aiva \u0433\u043E\u0432\u043E\u0440\u0438\u0442]\u2014</p><blockquote><p><strong>\u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(up\u0101ya\u1E25)</em>||6||</strong></p></blockquote><p>\u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em> [\u2014 \u044D\u0442\u043E \u0442\u043E\u0442, \u043A\u0442\u043E] \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u0435\u0442 <em>(g\u1E5B\u1E47\u0101ti)</em> [\u0438] \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0435\u0442 <em>(upadi\u015Bati)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u0439 <em>(t\u0101ttvikam)</em> \u0441\u043C\u044B\u0441\u043B <em>(artham iti)</em>. \u041E\u043D <em>(sa\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(up\u0101ya\u1E25)</em>, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u043C <em>(pradar\u015Bakatvena)</em> Vy\u0101pti <em>(vy\u0101pti)</em><sup>1</sup>|</p><p>\u0412\u043E\u0442 <em>(tad)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaye)</em>, [\u043A\u043E\u0433\u0434\u0430 \u015Aiva \u0433\u043E\u0432\u043E\u0440\u0438\u0442 P\u0101rvat\u012B]:</p><blockquote><p>&quot;[\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E,] \u043E\u043D <em>(sa\u1E25)</em> \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(prokta\u1E25)</em> \u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em>, \u0440\u0430\u0432\u043D\u044B\u043C <em>(sama\u1E25)</em> \u041C\u043D\u0435 <em>(mad)</em>, [\u043A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 \u0432\u0441\u0435 \u044D\u0442\u0438 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u043A\u0430\u043A\u043E\u0432\u044B \u043E\u043D\u0438 \u0435\u0441\u0442\u044C \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 <em>(prak\u0101\u015Baka\u1E25)</em> \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 \u0441\u0438\u043B\u0443 <em>(v\u012Brya)</em> \u043C\u0430\u043D\u0442\u0440 <em>(mantra... iti)</em>&quot;|<sup>2</sup><br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra II, 10]</p></blockquote><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0430\u043A\u0430\u044F [\u0442\u0435\u043C\u0430] \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 --\u0442.\u0435. \u043E \u0413\u0443\u0440\u0443 \u0438 \u0442.\u0434.-- <em>(evam-\u0101di-prasiddhatv\u0101t)</em>, \u043E\u043D\u0430 \u043D\u0435 \u0431\u044B\u043B\u0430 <em>(na)</em> \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0430 <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande tu)</em>|</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(ca)</em>, \u044D\u0442\u0430 [\u0442\u0435\u043C\u0430] <em>(etad)</em> \u0431\u044B\u043B\u0430 [\u043A\u0430\u043A-\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u0430 <em>(api sa\u1E45g\u1E5Bh\u012Btam eva)</em> \u0432 \u0444\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0445 <em>(p\u0101ryantika)</em> \u0441\u043B\u043E\u0432\u0430\u0445 <em>(ukty\u0101)</em> [\u044D\u0442\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] --\u0442.\u0435. \u0432 \u043F\u0440\u0435\u0434\u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 Spandak\u0101rik\u0101-s--:</p><blockquote><p>&quot;\u042F \u0432\u043E\u0437\u0434\u0430\u044E \u0434\u0430\u043D\u044C \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u044F <em>(vande)</em> \u044D\u0442\u043E\u0439 <em>(t\u0101m)</em> \u0437\u0430\u043C\u0435\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 <em>(citr\u0101m)</em> \u0440\u0435\u0447\u0438 <em>(bh\u0101rat\u012Bm)</em> \u0413\u0443\u0440\u0443 <em>(guru)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F [\u043F\u043E\u043B\u043D\u0430] \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 <em>(vicitra)</em> \u0441\u043B\u043E\u0432 --pada-- <em>(pad\u0101m)</em> [\u0441 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C\u0438 \u0438\u043C] \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F\u043C\u0438 <em>(artha)</em>, [\u0438] \u0434\u0430\u0435\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C <em>(t\u0101ri\u1E47\u012Bm)</em> \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E \u043F\u0435\u0440\u0435\u0441\u0435\u0447\u044C <em>(samuttara\u1E47a)</em> \u0431\u0435\u0437\u0434\u043E\u043D\u043D\u044B\u0439 <em>(ag\u0101dha)</em> \u043E\u043A\u0435\u0430\u043D <em>(ambhodhi)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(sa\u1E41\u015Baya... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s IV, 1]</p></blockquote><p>\u0418\u043B\u0438 <em>(v\u0101)</em> \u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em> [\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043E\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u043E\u0432\u0430\u043D \u043A\u0430\u043A] \u0434\u0430\u0440\u0443\u044E\u0449\u0430\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u044C <em>(anugr\u0101hik\u0101)</em> \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(p\u0101rama-\u012B\u015Bvar\u012B)</em>|</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaye)</em>:</p><blockquote><p>&quot;\u041A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em>, \u0447\u0442\u043E [\u0421\u0438\u043B\u0430, \u0434\u0430\u0440\u0443\u044E\u0449\u0430\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u044C ] <em>(tad eva)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, [\u0438] \u043E\u043D\u0430 <em>(tad)</em> [\u0435\u0441\u0442\u044C] \u0443\u0441\u0442\u0430 <em>(vaktram)</em> \u0413\u0443\u0440\u0443 <em>(guru... iti)</em>, \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(ucyate)</em> &quot;|</p></blockquote><p>\u0422\u0430\u043A\u0436\u0435 <em>(api)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Mantri\u015Birobhairava <em>(\u015Br\u012B-mantri\u015Birobhairave)</em>:</p><blockquote><p>&quot;\u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F <em>(gat\u0101)</em> \u0432 \u0443\u0441\u0442\u0430\u0445 <em>(vaktra)</em> \u0413\u0443\u0440\u0443 <em>(guru)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavet)</em> \u0431\u043E\u043B\u0435\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0439 <em>(gurutar\u0101)</em>, \u0447\u0435\u043C [\u0441\u0430\u043C] \u0413\u0443\u0440\u0443 <em>(guro\u1E25... iti)</em>&quot;|</p></blockquote><p>\u042D\u0442\u0430 \u0441\u0430\u043C\u0430\u044F [\u0421\u0438\u043B\u0430, \u0434\u0430\u0440\u0443\u044E\u0449\u0430\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u044C ] <em>(s\u0101 eva)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0430\u0435\u0442 <em>(dadat\u012B)</em> \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u0443\u044E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C <em>(avak\u0101\u015Bam)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(up\u0101ya\u1E25)</em>||6||</p><hr><ol><li><p>\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, &quot;Vy\u0101pti&quot; (\u0442.\u0435. \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043A\u0430\u043A &quot;\u0442\u043E, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043B\u0430 \u043C\u0430\u043D\u0442\u0440\u044B \u0438 \u0441\u0438\u043B\u0430 \u043C\u0443\u0434\u0440\u044B&quot;.</p></li><li><p>\u041E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0430\u044F \u043F\u0435\u0440\u0432\u0430\u044F \u0441\u0442\u0440\u043E\u043A\u0430 \u0432 \u0441\u0442\u0440\u043E\u0444\u0435: &quot;\u092F\u0903 \u092A\u0941\u0928\u0903 \u0938\u0930\u094D\u0935\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0928\u093F \u0935\u0947\u0924\u094D\u0924\u094D\u092F\u0947\u0924\u093E\u0928\u093F \u092F\u0925\u093E\u0930\u094D\u0925\u0924\u0903\u0964&quot; - &quot;Ya\u1E25 puna\u1E25 sarvatattv\u0101ni vettyet\u0101ni yath\u0101rthata\u1E25|&quot; \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u043B\u0430 \u0431\u044B\u0442\u044C \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B &quot;\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E...\u043A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 \u0432\u0441\u0435 \u044D\u0442\u0438 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u043A\u0430\u043A\u043E\u0432\u044B \u043E\u043D\u0438 \u0435\u0441\u0442\u044C \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438&quot; \u0432 \u0441\u043A\u043E\u0431\u043A\u0430\u0445 \u043A \u043C\u043E\u0435\u043C\u0443 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0443. OK, \u0442\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u043D\u043E.</p></li></ol></div>',1),i=[p];function o(u,k,s,n,d,v){return t(),e("div",null,i)}var q=a(r,[["render",o]]);export{l as __pageData,q as default};
